#!/usr/bin/env node
/**
 * @file build-whats-new.mjs
 *
 * Build-time script that extracts the current version's section from
 * the repo CHANGELOG.md and writes it as a TypeScript module to
 * extension/entrypoints/whats-new/whats-new.generated.ts. The
 * What's New page imports the module statically, so the release
 * notes are inlined into the page bundle at build time and there is
 * no runtime fetch.
 *
 * Why build-time and not runtime markdown parsing:
 *   - Avoids shipping a markdown library inside the extension bundle.
 *   - The CHANGELOG is generated by release-it from a constrained
 *     subset (headings, lists, links, bold, inline code), so a small
 *     hand-rolled converter covers every shape we expect.
 *
 * Output shape (TypeScript module):
 *   export interface WhatsNewPayload { version: string; html: string; generatedAt: string; }
 *   export const WHATS_NEW: WhatsNewPayload = { ... };
 *
 * Behaviour when the version section is missing (e.g., the release
 * has not been written to CHANGELOG.md yet): the script writes a
 * fallback HTML pointing the user at the GitHub release page so the
 * page never renders empty. The build does not fail.
 */

import { readFileSync, writeFileSync, mkdirSync, existsSync } from "node:fs";
import { dirname, resolve } from "node:path";
import { fileURLToPath } from "node:url";
import process from "node:process";

const __dirname = dirname(fileURLToPath(import.meta.url));
const REPO_ROOT = resolve(__dirname, "..", "..");
const CHANGELOG_PATH = resolve(REPO_ROOT, "CHANGELOG.md");
const PACKAGE_JSON_PATH = resolve(REPO_ROOT, "extension", "package.json");
const OUTPUT_DIR = resolve(REPO_ROOT, "extension", "entrypoints", "whats-new");
const OUTPUT_PATH = resolve(OUTPUT_DIR, "whats-new.generated.ts");

/** Read the version string from extension/package.json. */
function readExtensionVersion() {
  const pkg = JSON.parse(readFileSync(PACKAGE_JSON_PATH, "utf8"));
  if (typeof pkg.version !== "string" || !pkg.version) {
    throw new Error("extension/package.json is missing a version field");
  }
  return pkg.version;
}

/**
 * Extract the body of the section for the requested version from a
 * CHANGELOG.md string. Looks for `## [<version>]` and returns the
 * lines between that heading and the next `## [` heading (or EOF).
 * The heading line itself is not included — the page renders the
 * version into its own H1.
 *
 * Reference link definitions of the form `[id]: url` are filtered
 * out so they do not leak into the rendered HTML.
 *
 * Returns null when the version section cannot be found.
 */
function extractVersionSection(changelog, version) {
  const escaped = version.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
  const startRe = new RegExp(`^##\\s+\\[${escaped}\\]`);
  const lines = changelog.split(/\r?\n/);

  let start = -1;
  for (let i = 0; i < lines.length; i++) {
    if (startRe.test(lines[i])) {
      start = i;
      break;
    }
  }
  if (start === -1) return null;

  let end = lines.length;
  for (let i = start + 1; i < lines.length; i++) {
    if (/^##\s+\[/.test(lines[i])) {
      end = i;
      break;
    }
  }

  return lines
    .slice(start + 1, end)
    .filter((line) => !/^\[[^\]]+\]:\s+\S+/.test(line))
    .join("\n")
    .trim();
}

/** Escape HTML special characters in user-supplied text. */
function escapeHtml(text) {
  return text
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;");
}

/**
 * Allow only URL schemes that cannot execute script: https, http,
 * mailto, fragment-only references, and relative paths. Anything
 * else (notably `javascript:`, `data:`, `vbscript:`) is rejected.
 */
function isSafeUrl(url) {
  if (!url) return false;
  if (url.startsWith("#")) return true;
  if (url.startsWith("/") || url.startsWith("./") || url.startsWith("../")) return true;
  return /^(https?|mailto):/i.test(url);
}

/**
 * Apply inline markdown transformations to a single line. Order:
 * escape HTML first so user content cannot inject tags, then layer
 * in the trusted tags we generate (code, strong, em, a, img).
 *
 * Images are converted before links so `![alt](src)` does not get
 * picked up by the `[text](url)` link rule. Both link href and
 * image src run through `isSafeUrl`; rejected URLs are replaced
 * with `#` so the link text still renders.
 */
function inlineMarkdown(text) {
  return escapeHtml(text)
    .replace(/`([^`]+)`/g, "<code>$1</code>")
    .replace(/\*\*([^*]+)\*\*/g, "<strong>$1</strong>")
    .replace(/(^|[^*])\*([^*]+)\*(?!\*)/g, "$1<em>$2</em>")
    .replace(/!\[([^\]]*)\]\(([^)\s]+)\)/g, (_match, alt, src) => {
      const safeSrc = isSafeUrl(src) ? src : "#";
      return `<img src="${safeSrc}" alt="${alt}">`;
    })
    .replace(/\[([^\]]+)\]\(([^)\s]+)\)/g, (_match, label, url) => {
      const safeUrl = isSafeUrl(url) ? url : "#";
      return `<a href="${safeUrl}" rel="noopener noreferrer">${label}</a>`;
    });
}

/**
 * Convert a constrained-markdown section (the body extracted by
 * extractVersionSection) to safe HTML.
 *
 * Headings are demoted by one level: `### X` becomes `<h2>X</h2>`,
 * `#### X` becomes `<h3>X</h3>`. The page H1 is reserved for the
 * version banner, so the document outline goes H1 -> H2 -> H3 with
 * no skipped levels.
 */
function markdownToHtml(markdown) {
  const lines = markdown.split(/\r?\n/);
  const out = [];
  let listType = null;
  let inPara = false;
  let inCodeBlock = false;
  let codeLines = [];

  const closeList = () => {
    if (listType) {
      out.push(`</${listType}>`);
      listType = null;
    }
  };
  const closePara = () => {
    if (inPara) {
      out.push("</p>");
      inPara = false;
    }
  };

  for (const raw of lines) {
    const line = raw.trimEnd();

    // Fenced code block delimiter: ``` optionally followed by a
    // language hint. The hint is dropped — content between fences
    // renders as a plain <pre><code> with HTML-escaped text.
    if (/^```/.test(line)) {
      if (inCodeBlock) {
        out.push(`<pre><code>${codeLines.join("\n")}</code></pre>`);
        codeLines = [];
        inCodeBlock = false;
      } else {
        closePara();
        closeList();
        inCodeBlock = true;
      }
      continue;
    }
    if (inCodeBlock) {
      codeLines.push(escapeHtml(raw));
      continue;
    }

    if (!line.trim()) {
      closePara();
      closeList();
      continue;
    }

    const heading = /^(#{1,6})\s+(.+)$/.exec(line);
    if (heading) {
      closePara();
      closeList();
      const level = Math.min(6, Math.max(2, heading[1].length - 1));
      out.push(`<h${level}>${inlineMarkdown(heading[2])}</h${level}>`);
      continue;
    }

    const ulItem = /^[-*]\s+(.+)$/.exec(line);
    if (ulItem) {
      closePara();
      if (listType !== "ul") {
        closeList();
        out.push("<ul>");
        listType = "ul";
      }
      out.push(`  <li>${inlineMarkdown(ulItem[1])}</li>`);
      continue;
    }

    const olItem = /^\d+\.\s+(.+)$/.exec(line);
    if (olItem) {
      closePara();
      if (listType !== "ol") {
        closeList();
        out.push("<ol>");
        listType = "ol";
      }
      out.push(`  <li>${inlineMarkdown(olItem[1])}</li>`);
      continue;
    }

    closeList();
    if (!inPara) {
      out.push("<p>");
      inPara = true;
    } else {
      out.push(" ");
    }
    out.push(inlineMarkdown(line));
  }

  if (inCodeBlock) {
    out.push(`<pre><code>${codeLines.join("\n")}</code></pre>`);
  }
  closePara();
  closeList();
  return out.join("\n").replace(/<p>\n/g, "<p>");
}

/**
 * Build the fallback HTML for when CHANGELOG.md does not yet have a
 * section for the current version. Sends the user to the GitHub
 * release page so they can still read the notes.
 */
function fallbackHtml(version) {
  const tag = `v${escapeHtml(version)}`;
  const releaseUrl = `https://github.com/akash07k/butterswitch/releases/tag/${tag}`;
  return [
    "<p>",
    `Release notes for ${tag} are not bundled with this build.`,
    "</p>",
    "<p>",
    `Read them on GitHub: <a href="${releaseUrl}" rel="noopener noreferrer">${releaseUrl}</a>.`,
    "</p>",
  ].join("\n");
}

function main() {
  const version = readExtensionVersion();
  let html;

  if (!existsSync(CHANGELOG_PATH)) {
    process.stderr.write(
      `[build-whats-new] CHANGELOG.md not found at ${CHANGELOG_PATH}; writing fallback\n`,
    );
    html = fallbackHtml(version);
  } else {
    const changelog = readFileSync(CHANGELOG_PATH, "utf8");
    const section = extractVersionSection(changelog, version);
    if (!section) {
      process.stderr.write(
        `[build-whats-new] No CHANGELOG section for version ${version}; writing fallback\n`,
      );
      html = fallbackHtml(version);
    } else {
      html = markdownToHtml(section);
    }
  }

  if (!existsSync(OUTPUT_DIR)) {
    mkdirSync(OUTPUT_DIR, { recursive: true });
  }

  const generatedAt = new Date().toISOString();
  const module = [
    "// GENERATED FILE — do not edit. Source: CHANGELOG.md, generator: extension/scripts/build-whats-new.mjs",
    "",
    "export interface WhatsNewPayload {",
    "  version: string;",
    "  html: string;",
    "  generatedAt: string;",
    "}",
    "",
    "export const WHATS_NEW: WhatsNewPayload = {",
    `  version: ${JSON.stringify(version)},`,
    `  html: ${JSON.stringify(html)},`,
    `  generatedAt: ${JSON.stringify(generatedAt)},`,
    "};",
    "",
  ].join("\n");
  writeFileSync(OUTPUT_PATH, module, "utf8");
  process.stdout.write(
    `[build-whats-new] Wrote ${OUTPUT_PATH} (version ${version}, ${html.length} chars)\n`,
  );
}

main();
